@code {
    private int _currentStep = 1;
    private Order _order = new();

    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private void GoToPayment()
    {
        _currentStep = 2;
    }

    private void GoBackToShipping()
    {
        _currentStep = 1;
    }

    private async Task PlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

<h2>Checkout</h2>

<div class="checkout-wizard">
    @if (_currentStep == 1)
    {
        <ShippingStep Shipping="_order.Shipping" OnNext="GoToPayment" />
    }
    else if (_currentStep == 2)
    {
        <PaymentStep Payment="_order.Payment" OnBack="GoBackToShipping" OnPlaceOrder="PlaceOrder" />
    }
</div>

@implements IDisposable
@inject IAddressValidator AddressValidator

@code {
    private CancellationTokenSource? _cts;
    private bool _isValidating;
    private string? _validationError;

    [Parameter]
    public ShippingInfo Shipping { get; set; } = new();

    [Parameter]
    public EventCallback OnNext { get; set; }

    private async Task ValidateAndProceed()
    {
        // Cancel any previous in-flight validation
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _isValidating = true;
        _validationError = null;

        try
        {
            var isValid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (isValid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _validationError = "The address could not be verified. Please check and try again.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was cancelled — no action needed
        }
        finally
        {
            _isValidating = false;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

<h3>Shipping Information</h3>

<div class="form-group">
    <label for="name">Name</label>
    <input id="name" @bind="Shipping.Name" @bind:event="oninput" />
</div>

<div class="form-group">
    <label for="address">Address</label>
    <input id="address" @bind="Shipping.Address" @bind:event="oninput" />
</div>

<div class="form-group">
    <label for="city">City</label>
    <input id="city" @bind="Shipping.City" @bind:event="oninput" />
</div>

<div class="form-group">
    <label for="zip">Zip Code</label>
    <input id="zip" @bind="Shipping.ZipCode" @bind:event="oninput" />
</div>

@if (_validationError is not null)
{
    <div class="validation-error">@_validationError</div>
}

<button @onclick="ValidateAndProceed" disabled="@_isValidating">
    @if (_isValidating)
    {
        <span class="spinner"></span>
        <span>Validating...</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

